function LFDTUnitViewMgr:CreateNPCObj(grid,gridTrans,loadCb)
    ---@type LFDTUnitData
    local data = LFDTUnitData:New()
    data:SetData(grid,LFastDTUnitViewConst.NPC)

    ---@type LFDTUnitView
